    "xay-dung": BuildingOffice2Icon,
    "y-te-cham-soc-suc-khoe": HeartIcon,
    "du-lich-khach-san": HomeModernIcon,
    "gd-dao-tao": AcademicCapIcon,
    "kien-truc-thiet-ke": PaintBrushIcon,
